// Validate and normalise incoming task payload
const body = $input.first().json.body;

if (!body.task) throw new Error('Missing required field: task');

const branch = body.branch || `feat/${Date.now()}-${body.task.slice(0,20).toLowerCase().replace(/[^a-z0-9]/g,'-')}`;
const priority = body.priority || 'normal';
const files = body.files || [];

// Build the Manus prompt
const prompt = [
  `You are working on the Living Nexus platform (GitHub: livingnexus repo).`,
  `Clone the repo, checkout branch: ${branch} (create from main if it doesn't exist).`,
  `Task: ${body.task}`,
  files.length ? `Focus files: ${files.join(', ')}` : '',
  `When done: commit all changes with a clear message and push branch ${branch}.`,
  `Do NOT push to main. Do NOT merge. Push only to ${branch}.`,
  `Run pnpm test before pushing. If tests fail, fix them first.`,
].filter(Boolean).join('\n');

return [{
  json: {
    branch,
    priority,
    files,
    original_task: body.task,
    manus_prompt: prompt,
    created_at: new Date().toISOString(),
  }
}];

